import { SERVICE_CATEGORIES } from "./service-categories";

export type RichImage = {
  src: string;
  alt: string;
  /**
   * How this image should fill its hero frame.
   * - "contain" (default): good for product renders / cutouts on a
   *   cream card (keeps the whole image visible, no crop)
   * - "cover": good for lifestyle/install photos — fills the frame
   *   by cropping to fit
   */
  fit?: "contain" | "cover";
  /**
   * Crop anchor for "cover" images. Defaults to "center". Set to
   * "top" when the subject sits at the top of the source frame and
   * the bottom edge contains less-important context (sky, floor).
   */
  position?: "center" | "top" | "bottom";
};

export type RichItem = {
  heading?: string;
  body: string;
  image?: RichImage;
};

export type RichSection = {
  heading: string;
  intro?: string;
  items?: RichItem[];
};

export type RichPromo = {
  heading: string;
  image: RichImage;
  groups: { heading: string; items: string[] }[];
  disclaimer?: string;
};

export type RichFAQ = {
  heading: string;
  intro?: string;
  items: { q: string; a: string }[];
};

export type RichContent = {
  sections?: RichSection[];
  promo?: RichPromo;
  faq?: RichFAQ;
};

export type ServicePage = {
  slug: string;
  category: "Plumbing" | "Heating" | "Air" | "Water";
  /** City this page targets. Defaults to "Calgary" when omitted. */
  location?: "Calgary" | "Airdrie" | "Chestermere" | "Cochrane" | "Okotoks" | "Carstairs";
  icon: string;
  title: string;
  /** First hero paragraph (strong lead). */
  lead: string;
  /** Fallback short description used by generic template. */
  intro: string;
  /** Additional hero paragraphs rendered under the lead. */
  heroBody?: string[];
  /** Small kicker/subhead shown under hero body (e.g. "Satisfaction Guaranteed"). */
  heroSubhead?: string;
  /** Badge image shown next to the hero subhead (e.g. 5-star reviews). */
  heroBadgeImage?: RichImage;
  features: string[];
  bullets: { t: string; d: string }[];
  callout?: string;
  heroImage?: RichImage;
  richContent?: RichContent;
  /** SEO */
  seoTitle?: string;
  seoDescription?: string;
  seoKeywords?: string[];
  /** Schema.org price range hint for the Service.offers. Free-form string
   *  per the Schema spec ("$$", "$$$", "$5,500-$12,000", etc). When set,
   *  the Service node gets an offers block — useful for cost-intent SERP
   *  features on installation/replacement pages. */
  priceRange?: string;
  /** Optional image rendered below a specific richContent section. Key = section heading. */
  sectionImages?: Record<string, RichImage>;
  /** Quadrant / area-hub neighbourhood grid. When set, the page renders a
   *  compact card-grid section listing every neighbourhood landing page that
   *  belongs to this area. Drives both UX (jump to your neighbourhood) and
   *  SEO (deep internal linking from the hub to each spoke). Only set on
   *  the three Calgary quadrant pages today. */
  neighbourhoodHub?: {
    heading: string;
    intro: string;
    neighbourhoods: { name: string; slug: string; blurb?: string }[];
  };
  /** Per-service sticky sidebar copy (falls back to generic defaults). */
  sidebar?: {
    title?: string;
    subtitle?: string;
    bullets?: string[];
  };
  /** Stats strip rendered directly under the hero (4 items). */
  stats?: { number: string; label: string; icon?: string }[];
  /** Short noun for the quote-form heading ("AC", "boiler", "drain"). */
  quoteFormLabel?: string;
  /**
   * When set, the hero renders a "Financing Available" badge with the
   * Financeit logo. Only enable for bigger-ticket services (AC,
   * furnaces, boilers, heat pumps, PolyB, tankless heaters, water
   * softeners, hot water tanks). Leave undefined for service calls /
   * repairs / small jobs.
   */
  financing?: {
    detail?: string; // e.g. "Monthly payments · OAC via Financeit"
  };
  /**
   * Optional service-specific process timeline. When omitted the
   * template renders a generic 4-step timeline.
   */
  timeline?: {
    heading?: string;
    intro?: string;
    steps: { icon: string; title: string; body: string }[];
  };
  /**
   * Optional placeholder copy for the "Describe the issue" textarea
   * on the quote form. Makes the field feel tailored per service.
   */
  quoteFormPlaceholder?: string;
  /**
   * Optional photo portfolio rendered as a scroll-snap carousel between
   * the process timeline and related services. Use sparingly — best on
   * install-focused pages where "here's our work" lands.
   */
  portfolio?: {
    eyebrow?: string;
    heading?: string;
    intro?: string;
    items: { src: string; alt: string; caption?: string }[];
  };
  /**
   * Optional before/after image pairs rendered as drag-to-reveal sliders.
   * Best on pages where we have actual install transformations (furnace
   * swap-outs, boiler replacements, fixture upgrades).
   */
  beforeAfter?: {
    eyebrow?: string;
    heading?: string;
    intro?: string;
    pairs: {
      before: { src: string; alt: string };
      after: { src: string; alt: string };
      caption?: string;
    }[];
  };
  /**
   * Optional hub-and-spoke link grid for umbrella service pages
   * (`/boilers`, `/furnaces`, `/hot-water-tanks`). Concentrates link
   * equity inward to deeper sibling service pages.
   */
  hubLinks?: {
    eyebrow?: string;
    heading?: string;
    intro?: string;
    items: {
      label: string;
      href: string;
      summary: string;
      icon?: string;
      /** When true, the card renders with the brand-red highlight
       *  treatment — emergency border, "Common issue" badge, slightly
       *  larger visual weight. Use for pages we want to surface
       *  prominently on the hub (e.g. issue-diagnosis pages that
       *  intentionally aren't in the main nav). */
      highlight?: boolean;
      /** Custom badge text when highlight=true. Defaults to
       *  "Common issue" when omitted. */
      badge?: string;
    }[];
  };
};

